import React from "react";
import { Container, Row, Col, Card } from "react-bootstrap";
import { useAuth } from "../context/AuthContext";

function Dashboard() {
  const { user } = useAuth();

  return (
    <Container className="mt-4">
      <h2 className="text-center mb-4">Welcome, {user ? user.name || "User" : "Guest"}!</h2>
      <Row>
        <Col md={4}>
          <Card className="p-4 text-center shadow-sm">
            <i className="bi bi-capsule display-4 text-primary"></i>
            <h5 className="mt-3">Medications</h5>
          </Card>
        </Col>
        <Col md={4}>
          <Card className="p-4 text-center shadow-sm">
            <i className="bi bi-calendar-event display-4 text-success"></i>
            <h5 className="mt-3">Appointments</h5>
          </Card>
        </Col>
        <Col md={4}>
          <Card className="p-4 text-center shadow-sm">
            <i className="bi bi-chat-dots display-4 text-info"></i>
            <h5 className="mt-3">Forum</h5>
          </Card>
        </Col>
      </Row>
    </Container>
  );
}

export default Dashboard;
